using System.Linq;

class CosmosQuery
{
    // EF Core 9 Cosmos provider no longer supports synchronous I/O — all queries must be async.
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — still works because we preserved "Discriminator" as the
        // discriminator property name via HasDiscriminator<string>("Discriminator").
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // Sync ToList() throws in EF Core 9 Cosmos; use ToListAsync() instead.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

